SELECT
DATE_TRUNC('hour', insert_date_time) DATE_TRUNC('day', insert_date_time) GREATEST(DATE_TRUNC('month', insert_date_time), DATE_TRUNC('week', insert_date_time)) DATE_TRUNC('month', insert_date_time)
AS aggregated_date_time, status_name, COUNT(*) AS sales_count FROM sale_history WHERE valid_flg = true
AND user_team_code = #{userTeamCode,jdbcType=VARCHAR}
AND user_id = #{userId,jdbcType=INTEGER}
AND user_company_code = #{userCompanyCode,jdbcType=VARCHAR}
AND insert_date_time >= #{searchStartDate,jdbcType=TIMESTAMP} AND insert_date_time < #{searchEndDate,jdbcType=TIMESTAMP} GROUP BY
DATE_TRUNC('hour', insert_date_time) DATE_TRUNC('day', insert_date_time) GREATEST(DATE_TRUNC('month', insert_date_time), DATE_TRUNC('week', insert_date_time)) DATE_TRUNC('month', insert_date_time) , status_name ORDER BY aggregated_date_time
